html:
{%- set emp = doc -%}
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Employee ID Card — {{ emp.full_name }}</title>
</head>
<body style="margin:0;padding:32px;background:#f0f2f5;
             font-family:'Segoe UI',Arial,sans-serif;
             display:flex;justify-content:center;align-items:center;
             min-height:100vh;box-sizing:border-box;">

  <!-- Card wrapper -->
  <div style="width:340px;border-radius:16px;overflow:hidden;
              box-shadow:0 8px 32px rgba(0,0,0,0.18);
              background:#ffffff;">

    <!-- ── Header band ── -->
    <div style="background:linear-gradient(135deg,#1a3c5e 0%,#2d6a9f 100%);
                padding:28px 24px 20px;text-align:center;position:relative;">

      <!-- Company / app name -->
      <div style="font-size:11px;font-weight:700;letter-spacing:2px;
                  color:rgba(255,255,255,0.6);text-transform:uppercase;
                  margin-bottom:16px;">
        {{ frappe.db.get_default("company") or "Your Company" }}
      </div>

      <!-- Photo -->
      <div style="width:90px;height:90px;border-radius:50%;
                  border:3px solid rgba(255,255,255,0.85);
                  margin:0 auto 12px;overflow:hidden;
                  background:#e8edf2;display:flex;
                  align-items:center;justify-content:center;">
        {%- if emp.profile_photo %}
          <img src="{{ emp.profile_photo }}"
               alt="{{ emp.full_name }}"
               style="width:100%;height:100%;object-fit:cover;display:block;">
        {%- else %}
          <!-- Fallback initials avatar -->
          <span style="font-size:30px;font-weight:700;
                       color:#2d6a9f;line-height:1;">
            {{ (emp.first_name[0] if emp.first_name else "") }}{{ (emp.last_name[0] if emp.last_name else "") }}
          </span>
        {%- endif %}
      </div>

      <!-- Full name -->
      <div style="font-size:18px;font-weight:700;color:#ffffff;
                  letter-spacing:0.3px;margin-bottom:4px;">
        {{ emp.full_name }}
      </div>

      <!-- Designation pill -->
      {%- if emp.designation %}
      <div style="display:inline-block;background:rgba(255,255,255,0.18);
                  border:1px solid rgba(255,255,255,0.35);
                  border-radius:20px;padding:3px 14px;
                  font-size:11px;color:rgba(255,255,255,0.92);
                  letter-spacing:0.5px;margin-top:2px;">
        {{ emp.designation }}
      </div>
      {%- endif %}
    </div>

    <!-- ── ID badge strip ── -->
    <div style="background:#2d6a9f;padding:6px 24px;
                display:flex;justify-content:space-between;
                align-items:center;">
      <span style="font-size:10px;font-weight:600;
                   color:rgba(255,255,255,0.65);
                   text-transform:uppercase;letter-spacing:1px;">
        Employee ID
      </span>
      <span style="font-size:12px;font-weight:700;
                   color:#ffffff;letter-spacing:1px;">
        {{ emp.name }}
      </span>
    </div>

    <!-- ── Detail rows ── -->
    <div style="padding:20px 24px 8px;">

      {%- set rows = [
        ("Department",     emp.department,    "🏢"),
        ("Date of Joining", frappe.utils.formatdate(emp.date_of_joining), "📅"),
        ("Email",          emp.employee_email,"✉"),
        ("Phone",          emp.phone,         "📞"),
      ] %}

      {%- for label, value, icon in rows %}
        {%- if value %}
        <div style="display:flex;align-items:flex-start;
                    padding:9px 0;
                    border-bottom:1px solid #f0f2f5;">
          <span style="font-size:13px;width:22px;flex-shrink:0;
                       margin-top:1px;">{{ icon }}</span>
          <div style="flex:1;min-width:0;">
            <div style="font-size:9px;font-weight:700;
                        color:#94a3b8;text-transform:uppercase;
                        letter-spacing:0.8px;margin-bottom:1px;">
              {{ label }}
            </div>
            <div style="font-size:12px;color:#1e293b;
                        font-weight:500;word-break:break-word;">
              {{ value }}
            </div>
          </div>
        </div>
        {%- endif %}
      {%- endfor %}

    </div>

    <!-- ── Footer ── -->
    <div style="padding:14px 24px 20px;text-align:center;">
      <!-- Decorative barcode-style lines -->
      <div style="display:flex;justify-content:center;
                  gap:2px;margin-bottom:10px;">
        {%- for w in [2,1,3,1,2,1,4,1,2,3,1,2,1,3,2,1,2,1,3,1] %}
        <div style="width:{{ w }}px;height:28px;
                    background:#1a3c5e;opacity:0.7;
                    border-radius:1px;"></div>
        {%- endfor %}
      </div>
      <div style="font-size:9px;color:#94a3b8;letter-spacing:0.5px;">
        This card is company property. If found, please return.
      </div>
    </div>

  </div><!-- /card -->

</body>
</html>
